            val qout = col.backend.extractAvTags(text = qtext, questionSide = true)
            var qoutText = qout.text

            val atext = parseVideos(
                parseSourcesToFileScheme(
                    applyCustomFilters(partial.anodes, this, frontSide = qout.text),
                    mediaDir
                ),
                mediaDir
