 * 1. everything before the attribute name (the opening tag portion)
 * 2. the attribute name (`src` or `data`)
 * 3. the `=` sign
 * 4. the full attribute value token (including quotes if present)
 * 5. the value if double-quoted
 * 6. the value if single-quoted
 * 7. the value if unquoted
 */
private val SOURCE_ATTRIBUTE_REGEX = Regex(
    """(<(?:img|video|audio|source|object)\b[^>]*?\b)(src|data)(=)("([^"]*)"|'([^']*)'|([^\s>]+))""",
    RegexOption.IGNORE_CASE
)

