/**
 * Parses the sources of the `<img>`, `<video>`, `<audio>`, `<object>` and `<source>` tags
 * to use the `file:///` scheme, which allows seeking audio and videos,
 * and loads faster than using HTTP.
 *
 * Only attribute values that don't have a Uri scheme (http, file, etc) are parsed.
 */
@NotInLibAnki
@VisibleForTesting
fun parseSourcesToFileScheme(content: String, mediaDir: String): String {
    // Use Jsoup with the XML parser to find elements and determine replacements,
    // then apply those replacements to the original string.
    // This avoids using Jsoup's HTML serialization (doc.body().html()) which strips
    // <script> tags and their contents, breaking complex card templates that use JavaScript.
    val doc = Jsoup.parse(content, "", Parser.xmlParser())
    doc.outputSettings(OutputSettings().prettyPrint(false))

    data class Replacement(val oldAttrValue: String, val newAttrValue: String, val tag: String, val attr: String)

    val replacements = mutableListOf<Replacement>()

    fun findReplacements(tag: String, attr: String) {
        for (elem in doc.select(tag)) {
            val attrValue = elem.attr(attr)
            if (attrValue.isEmpty()) continue

            val attrUri = try {
                URI(attrValue)
            } catch (_: URISyntaxException) {
                continue
            }
            if (attrUri.scheme != null) continue

            val path = Paths.get(mediaDir, attrUri.path).toString()
            val newUri = getFileUri(path)

            replacements.add(Replacement(attrValue, newUri.toString(), tag, attr))
        }
    }

    findReplacements("img", "src")
    findReplacements("video", "src")
    findReplacements("audio", "src")
    findReplacements("source", "src")
    findReplacements("object", "data")

    if (replacements.isEmpty()) {
        return content
    }

    // Apply replacements using regex on the original content string to preserve <script> tags
    var result = content
    for (replacement in replacements) {
        val oldValue = Regex.escape(replacement.oldAttrValue)
        val tag = replacement.tag
        val attr = replacement.attr
        // Match the attribute within the specific tag, handling quoted and unquoted values
        // Case-insensitive to handle uppercase tags/attributes
        val pattern = Regex(
            """(<$tag\b[^>]*?\b$attr\s*=\s*)(?:"${oldValue}"|'${oldValue}'|${oldValue})""",
            RegexOption.IGNORE_CASE
        )
        result = pattern.replaceFirst(result) { match ->
            """${match.groupValues[1].lowercase()}"${replacement.newAttrValue}""""
        }
    }

    return result
}

