}

/**
 * The desktop version handles videos in an external player (mpv)
 * because of old webview codecs in python, and to allow extending the video player.
 * To simplify things and deliver a better result,
 * we use the webview player, like AnkiMobile does
 *
 * `file:///` is used to enable seeking the video
 */
@NotInLibAnki
@VisibleForTesting
fun parseVideos(text: String, mediaDir: String): String {
    return SOUND_RE.replace(text) { match ->
        val fileName = match.groupValues[1]
        val extension = fileName.substringAfterLast(".", "")
        if (extension in VIDEO_EXTENSIONS) {
            val path = Paths.get(mediaDir, fileName).toString()
            val uri = getFileUri(path)

            @Language("HTML")
            val result =
                """<video src="$uri" controls controlsList="nodownload"></video>"""
            result
        } else {
            match.value
        }
    }
}

/**
 * Regex that matches `src` or `data` attributes within `<img>`, `<video>`, `<audio>`,
 * `<source>` and `<object>` tags. Attribute values can be double-quoted, single-quoted
 * or unquoted.
 *
 * Groups:
 * 1. the opening tag up to the attribute name (e.g. `<img ` or `<video controls `)
 * 2. the attribute name (`src` or `data`)
 * 3. the `=` sign (possibly surrounded by whitespace)
 * 4. the full attribute value token (including quotes if present)
 * 5. the value if double-quoted
 * 6. the value if single-quoted
 * 7. the value if unquoted
 */
private val SOURCE_ATTRIBUTE_REGEX = Regex(
    """(<(?:img|video|audio|source|object)\b[^>]*?\b)(src|data)(\s*=\s*)("([^"]*)"|'([^']*)'|([^\s>]+))""",
    RegexOption.IGNORE_CASE
)

