 * Parses the sources of the `<img>`, `<video>`, `<audio>`, `<object>` and `<source>` tags
 * to use the `file:///` scheme, which allows seeking audio and videos,
 * and loads faster than using HTTP.
 *
 * Only attribute values that don't have a Uri scheme (http, file, etc) are parsed.
 *
 * Uses regex-based replacement instead of Jsoup serialization to preserve
 * `<script>` tags and other content that Jsoup would strip or modify.
 */
@NotInLibAnki
@VisibleForTesting
fun parseSourcesToFileScheme(content: String, mediaDir: String): String {
    var result = content
    var madeChanges = false

    // Process matches from end to start to preserve string indices when making replacements
    val matches = SOURCE_ATTRIBUTE_REGEX.findAll(content).toList().reversed()

    for (match in matches) {
        // The attribute value is in group 5 (double-quoted), 6 (single-quoted), or 7 (unquoted)
        val attrValue = match.groupValues[5].ifEmpty { match.groupValues[6].ifEmpty { match.groupValues[7] } }
        if (attrValue.isEmpty()) continue

        val attrUri = try {
            URI(attrValue)
        } catch (_: URISyntaxException) {
            continue
        }
        if (attrUri.scheme != null) continue

        val path = Paths.get(mediaDir, attrUri.path).toString()
        val newUri = getFileUri(path)

        // Replace the attribute name + value portion: e.g. src="old" -> src="new_uri"
        // Lowercase the attribute name to match standard HTML conventions
        val replacement = "${match.groupValues[2].lowercase()}=\"$newUri\""
        val attrStart = match.groups[2]!!.range.first
        val attrEnd = match.groups[4]!!.range.last + 1
        result = result.substring(0, attrStart) + replacement + result.substring(attrEnd)
        madeChanges = true
    }

    return if (madeChanges) result else content
}

/** Similar to [File.toURI], but doesn't use the absolute file to simplify testing */
@NotInLibAnki
@VisibleForTesting
fun getFileUri(path: String): URI {
    var p = path
    if (File.separatorChar != '/') p = p.replace(File.separatorChar, '/')
    if (!p.startsWith("/")) p = "/$p"
    if (!p.startsWith("//")) p = "//$p"
    return URI("file", p, null)
