        }
        if (attrUri.scheme != null) continue

        val path = Paths.get(mediaDir, attrUri.path).toString()
        val newUri = getFileUri(path)

        // Replace the tag name (lowercased) + attribute name (lowercased) + value
        // Group 1: `<`
        // Group 2: tag name -> lowercase
        // Group 3: content between tag name and attr -> preserved
        // Group 4: attr name -> lowercase
        // Group 5: `=` -> replaced with `=`
        // Group 6: old value -> replaced with new quoted value
        val replacement = "${match.groupValues[1]}${match.groupValues[2].lowercase()}${match.groupValues[3]}${match.groupValues[4].lowercase()}=\"$newUri\""
        val replStart = match.groups[1]!!.range.first
        val replEnd = match.groups[6]!!.range.last + 1
        result = result.substring(0, replStart) + replacement + result.substring(replEnd)
        madeChanges = true
    }

    return if (madeChanges) result else content
